+// NativeEventsConfig — serde + Default
+// =============================================================================
+
+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(50))]
+
+    #[test]
+    fn prop_native_events_config_serde(
+        enabled in proptest::bool::ANY,
